VALUES
  ('judicial-57f41407-moex-00023', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '1990年代後，全球的主權國家以自由民主體制為主，政治學界也持續對民主體制展開研究，關於學界對民 主的研究，下列敘述何者最難以被否證？', '["研究非民主國家的政治、經濟與社會發展對於民主研究沒有貢獻", "自由民主體制包含多個要件，舉辦選舉與保障言論自由，兩者同等重要", "民粹主義跟民主退潮無關", "相較於議會內閣制，大黨在實施總統制的國家中更容易鞏固優勢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00024', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '我國已立法通過兩公約施行法與消除對婦女一切形式歧視公約施行法，並針對這些公約定期提出國家報 告，且邀請國外學者專家來臺灣進行審查。我國依前述公約內容推動人權保障，下列敘述何者正確？', '["相較於比例代表制，推動單一選區制更有利於婦女候選人當選", "性少數群體權益的保障，也是一種人權保障的落實", "臺灣政府從未邀請國際非政府組織代表參與國家報告審查", "國際人權學者很肯定臺灣對外籍家務勞工勞動權的保障"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00025', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '下列何者不是關於政府民主正當性的描述？', '["人民有投票選舉政府領導人之權利", "政府行政行為均應有嚴謹法律規定之授權", "國家法律是由人民選舉之代表所制定", "政府之施政應探求最新民意並作相應之調整"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00026', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '下列何者不是我國憲法所明文保障之公民權利？', '["健康權", "訴願權", "工作權", "秘密通訊自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00027', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '下列各項權利，何者屬於我國法律所保障之原住民族集體權利？', '["受教權", "正名權", "繼承權", "擁槍權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00028', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '某私立高中擬放寬服裝儀容規定，下列敘述何者正確？', '["因為屬私立高中，基於私法自治，學校可全權決定服儀規定", "高中生屬於未成年人，家長得否決放寬決定", "高中生屬於未成年人，但仍應該給予參與決策的權利", "應該給予制服廠商表示意見的機會，以保障其契約自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00029', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '1948年聯合國通過「世界人權宣言」，下列敘述何者正確？', '["國際社會首度界定人權的概念", "要求國家積極給予人民協助，保障人民的社會權", "會員國的國民才擁有世界人權宣言所列的權利", "會員國國民可以直接依據世界人權宣言，向各國法院起訴主張人權受侵害"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
